import{_ as r,o as t,c as n,j as e,a as s,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.3.对特定部位攻击","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.3.对特定部位攻击.md","filePath":"1.基础规则/3.战斗规则/3.3.对特定部位攻击.md"}'),o={name:"1.基础规则/3.战斗规则/3.3.对特定部位攻击.md"};function d(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_3-3-对特定部位攻击",tabindex:"-1"},[s("3.3.对特定部位攻击 "),e("a",{class:"header-anchor",href:"#_3-3-对特定部位攻击","aria-label":'Permalink to "3.3.对特定部位攻击"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),_('<h1 id="对特定部位攻击" tabindex="-1">对特定部位攻击 <a class="header-anchor" href="#对特定部位攻击" aria-label="Permalink to &quot;对特定部位攻击&quot;">​</a></h1><p>对特定部位攻击</p><p>这是指定攻击敌人身上某处要害的动作。<br> 对特定部位攻击一般来说视为一次普通的攻击，如无特别说明，则你可以在这次攻击中使用任何特殊能力或招式。需要注意的是，只有指定具体目标的攻击可以进行部位攻击，而范围性攻击若无特殊说明通常不能指定部位攻击。<br> 视攻击部位而定，你在这次攻击中受到一定的减值。若被攻击者意识到了你的这次攻击且保有基本防御（这意味着他没有处于措手不及或类似定身的状态），他在防御上获得与你受到的减值数量相同的闪避加值。抵御以此法造成的异常点数（包括肢体妨碍）时，使用标准豁免进行对抗<br> 攻击特定部位会有不同的特殊效果，视情况而定，除去击落武器外，这些特殊效果均视为C级创伤来源的效果。以下是一些范例：<br> 攻击头部：减值3，每2点伤害造成1点晕眩，以耐力-求生-强韧对抗。<br> 攻击腹部：减值2，每1点伤害造成1点恶心，以耐力-求生-强韧或决心-求生-强韧对抗。<br> 攻击肋骨或鼻梁：减值3，每2伤害造成1点剧痛，以耐力-求生-强韧对抗<br> 击落武器：减值3，不造成伤害，以力量-武技-对应武器专业对抗，失败则武器脱手。若攻击方以手或类似结构的天生武器进行攻击，可夺取武器。<br> 攻击肢体：减值2，每2点伤害造成指定肢体的1点肢体妨碍，以耐力-求生-强韧或敏捷-求生-强韧对抗</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
